SELECT `p`.`id`
FROM `pengurus` `p`
INNER JOIN `tmp_candidate_pengurus_20260509` `c` ON `c`.`id` = `p`.`id`
WHERE `p`.`created_at` BETWEEN @migration_window_start AND @migration_window_end
