FROM `pengurus` `p`
INNER JOIN `tmp_safe_pengurus_20260509` `s` ON `s`.`id` = `p`.`id`;

SELECT COUNT(*) INTO @candidate_pengurus FROM `tmp_candidate_pengurus_20260509`;
SELECT COUNT(*) INTO @safe_pengurus FROM `tmp_safe_pengurus_20260509`;
SELECT COUNT(*) INTO @backup_pengurus FROM `rollback_20260509_generated_pengurus` `b` INNER JOIN `tmp_safe_pengurus_20260509` `s` ON `s`.`id` = `b`.`id`;
DELETE `p` FROM `pengurus` `p` INNER JOIN `tmp_safe_pengurus_20260509` `s` ON `s`.`id` = `p`.`id`;
SET @deleted_pengurus = ROW_COUNT();

VALUES ('pengurus', @candidate_pengurus, @safe_pengurus, @backup_pengurus, @deleted_pengurus)
ON DUPLICATE KEY UPDATE
